static void minmax_scale_clf(const float *raw, float *scaled) {
    for (int i = 0; i < N_CLF_FEATURES; i++) {
        float range = clf_data_max[i] - clf_data_min[i];
        scaled[i] = (range != 0.0f) ? (raw[i] - clf_data_min[i]) / range : 0.0f;
    }
}

/* raw da qua log10 (voi mag) hoac chua (voi phase) truoc khi goi ham nay */
static void robust_scale(const float *raw, const float *center, const float *scale, int n, float *out) {
    for (int i = 0; i < n; i++) {
        out[i] = (scale[i] != 0.0f) ? (raw[i] - center[i]) / scale[i] : 0.0f;
    }
}

static void log10_array(const float *raw, int n, float *out) {
    for (int i = 0; i < n; i++) out[i] = log10f(raw[i]);
}

