/* Tra ve index class co xac suat trung binh cao nhat (giong        */
/* RandomForestClassifier.predict() cua sklearn: trung binh          */
/* predict_proba() cua tat ca cac cay roi argmax).                   */
static int rf_predict(const float *x_scaled, float *proba_sum_out /* size RF_N_CLASSES, co the NULL */) {
    float proba_sum[RF_N_CLASSES] = {0};
    float proba[RF_N_CLASSES];
    for (int t = 0; t < RF_N_TREES; t++) {
        rf_tree_funcs[t](x_scaled, proba);
        for (int c = 0; c < RF_N_CLASSES; c++) proba_sum[c] += proba[c];
    }
    int best = 0;
    for (int c = 1; c < RF_N_CLASSES; c++) {
        if (proba_sum[c] > proba_sum[best]) best = c;
    }
    if (proba_sum_out) {
        for (int c = 0; c < RF_N_CLASSES; c++) proba_sum_out[c] = proba_sum[c];
    }
    return best;
}


/* ============================================================ */
/* Giai doan 2: Cac layer CNN thuan C (dung chung cho moi label) */
/* ============================================================ */
#define SEQ_LEN    15    /* so diem tan so (mag/phase) */
#define POOL1_LEN  7    /* do dai sau MaxPool1d(kernel=2) */

static void conv1d_pad1(const float *input, int in_ch, int len,
                         const float *weight, const float *bias,
                         int out_ch, int k, float *output) {
    int pad = 1;
    for (int oc = 0; oc < out_ch; oc++) {
        for (int t = 0; t < len; t++) {
            float sum = bias[oc];
            for (int ic = 0; ic < in_ch; ic++) {
                for (int kk = 0; kk < k; kk++) {
                    int in_t = t - pad + kk;
                    if (in_t >= 0 && in_t < len) {
                        sum += weight[(oc * in_ch + ic) * k + kk] * input[ic * len + in_t];
                    }
                }
            }
            output[oc * len + t] = sum;
        }
    }
}

static void batchnorm1d_relu(float *x, int ch, int len,
                              const float *gamma, const float *beta,
                              const float *mean, const float *var, float eps) {
    for (int c = 0; c < ch; c++) {
        float scale = gamma[c] / sqrtf(var[c] + eps);
        float shift = beta[c] - mean[c] * scale;
        for (int t = 0; t < len; t++) {
            float v = x[c * len + t] * scale + shift;
            x[c * len + t] = v > 0.0f ? v : 0.0f;  /* ReLU */
        }
    }
}

static void maxpool1d_k2(const float *input, int ch, int len, float *output) {
    int out_len = len / 2;
    for (int c = 0; c < ch; c++) {
        for (int t = 0; t < out_len; t++) {
            float a = input[c * len + 2 * t];
            float b = input[c * len + 2 * t + 1];
            output[c * out_len + t] = a > b ? a : b;
        }
    }
}

static void linear_layer(const float *input, int in_dim,
                          const float *weight, const float *bias,
                          int out_dim, int apply_relu, float *output) {
    for (int o = 0; o < out_dim; o++) {
        float sum = bias[o];
        for (int i = 0; i < in_dim; i++) sum += weight[o * in_dim + i] * input[i];
        output[o] = (apply_relu && sum < 0.0f) ? 0.0f : sum;
    }
}

