/* mag_scaled, phase_scaled: da qua log10 (chi mag) + RobustScaler, dai SEQ_LEN */
/* out: mang 1 phan tu, gia tri con o dang scaled-log (chua doi nguoc) */
static void cnn_forward_Resistor(const float *mag_scaled, const float *phase_scaled, float *out) {
    float input[2 * SEQ_LEN];
    for (int t = 0; t < SEQ_LEN; t++) {
        input[0 * SEQ_LEN + t] = mag_scaled[t];
        input[1 * SEQ_LEN + t] = phase_scaled[t];
    }

    float c1_out[Resistor_CONV1_OUT_CH * SEQ_LEN];
    conv1d_pad1(input, 2, SEQ_LEN, Resistor_conv1_weight, Resistor_conv1_bias, Resistor_CONV1_OUT_CH, 3, c1_out);
    batchnorm1d_relu(c1_out, Resistor_CONV1_OUT_CH, SEQ_LEN, Resistor_bn1_gamma, Resistor_bn1_beta, Resistor_bn1_mean, Resistor_bn1_var, Resistor_BN1_EPS);

    float p1_out[Resistor_CONV1_OUT_CH * POOL1_LEN];
    maxpool1d_k2(c1_out, Resistor_CONV1_OUT_CH, SEQ_LEN, p1_out);

    float c2_out[Resistor_CONV2_OUT_CH * POOL1_LEN];
    conv1d_pad1(p1_out, Resistor_CONV1_OUT_CH, POOL1_LEN, Resistor_conv2_weight, Resistor_conv2_bias, Resistor_CONV2_OUT_CH, 3, c2_out);
    batchnorm1d_relu(c2_out, Resistor_CONV2_OUT_CH, POOL1_LEN, Resistor_bn2_gamma, Resistor_bn2_beta, Resistor_bn2_mean, Resistor_bn2_var, Resistor_BN2_EPS);

    /* Flatten: c2_out da dung layout channel-major, khop voi nn.Flatten() */
    float fc1_out[Resistor_FNN1_OUT];
    linear_layer(c2_out, Resistor_FNN1_IN, Resistor_fnn1_weight, Resistor_fnn1_bias, Resistor_FNN1_OUT, 1, fc1_out);

    linear_layer(fc1_out, Resistor_FNN1_OUT, Resistor_fnn2_weight, Resistor_fnn2_bias, Resistor_FNN2_OUT, 0, out);
}

