static const float Parallel_RC_fnn2_bias[2] = {
    -0.08342189f, 0.02697838f
};


/* mag_scaled, phase_scaled: da qua log10 (chi mag) + RobustScaler, dai SEQ_LEN */
/* out: mang 2 phan tu, gia tri con o dang scaled-log (chua doi nguoc) */
static void cnn_forward_Parallel_RC(const float *mag_scaled, const float *phase_scaled, float *out) {
    float input[2 * SEQ_LEN];
    for (int t = 0; t < SEQ_LEN; t++) {
        input[0 * SEQ_LEN + t] = mag_scaled[t];
        input[1 * SEQ_LEN + t] = phase_scaled[t];
    }

    float c1_out[Parallel_RC_CONV1_OUT_CH * SEQ_LEN];
    conv1d_pad1(input, 2, SEQ_LEN, Parallel_RC_conv1_weight, Parallel_RC_conv1_bias, Parallel_RC_CONV1_OUT_CH, 3, c1_out);
    batchnorm1d_relu(c1_out, Parallel_RC_CONV1_OUT_CH, SEQ_LEN, Parallel_RC_bn1_gamma, Parallel_RC_bn1_beta, Parallel_RC_bn1_mean, Parallel_RC_bn1_var, Parallel_RC_BN1_EPS);

    float p1_out[Parallel_RC_CONV1_OUT_CH * POOL1_LEN];
    maxpool1d_k2(c1_out, Parallel_RC_CONV1_OUT_CH, SEQ_LEN, p1_out);

    float c2_out[Parallel_RC_CONV2_OUT_CH * POOL1_LEN];
    conv1d_pad1(p1_out, Parallel_RC_CONV1_OUT_CH, POOL1_LEN, Parallel_RC_conv2_weight, Parallel_RC_conv2_bias, Parallel_RC_CONV2_OUT_CH, 3, c2_out);
    batchnorm1d_relu(c2_out, Parallel_RC_CONV2_OUT_CH, POOL1_LEN, Parallel_RC_bn2_gamma, Parallel_RC_bn2_beta, Parallel_RC_bn2_mean, Parallel_RC_bn2_var, Parallel_RC_BN2_EPS);

    /* Flatten: c2_out da dung layout channel-major, khop voi nn.Flatten() */
    float fc1_out[Parallel_RC_FNN1_OUT];
    linear_layer(c2_out, Parallel_RC_FNN1_IN, Parallel_RC_fnn1_weight, Parallel_RC_fnn1_bias, Parallel_RC_FNN1_OUT, 1, fc1_out);

    linear_layer(fc1_out, Parallel_RC_FNN1_OUT, Parallel_RC_fnn2_weight, Parallel_RC_fnn2_bias, Parallel_RC_FNN2_OUT, 0, out);
}


/* ============================================================ */
/* API chinh: goi ham nay tu code STM32                          */
/* ============================================================ */
typedef struct {
    int label_idx;
    const char *label_str;
    float value_R;   /* Ohm, 0 neu khong ap dung */
    float value_C;   /* Farad, 0 neu khong ap dung */
} ModelTongResult;

/*
 * raw_mag15, raw_phase15: mang 15 phan tu, gia tri THO (chua qua log/scaler),
 * dung dung thu tu index 0..14 nhu luc train. Magnitude phai > 0 (dung log10).
 */
static ModelTongResult predict_configuration(const float *raw_mag15, const float *raw_phase15) {
    ModelTongResult result;

    /* ---- Giai doan 1: Classification (8 diem duoc chon) ---- */
    float clf_raw[N_CLF_FEATURES];
    for (int i = 0; i < N_SELECTED_IDX; i++) {
        int idx = selected_indices[i];
        clf_raw[2 * i]     = raw_mag15[idx];
        clf_raw[2 * i + 1] = raw_phase15[idx];
    }
    float clf_scaled[N_CLF_FEATURES];
    minmax_scale_clf(clf_raw, clf_scaled);

    result.label_idx = rf_predict(clf_scaled, NULL);
    result.label_str = class_names[result.label_idx];
    result.value_R = 0.0f;
    result.value_C = 0.0f;

    /* ---- Giai doan 2: chon dung CNN regressor theo Label vua du doan ---- */
    if (strcmp(result.label_str, "Resistor") == 0) {
        float mag_log[N_MAG];
        log10_array(raw_mag15, N_MAG, mag_log);

        float mag_scaled[N_MAG];
        float phase_scaled[N_PHASE];
        robust_scale(mag_log, Resistor_mag_center, Resistor_mag_scale, N_MAG, mag_scaled);
        robust_scale(raw_phase15, Resistor_phase_center, Resistor_phase_scale, N_PHASE, phase_scaled);

        float rc_scaled[1];
        cnn_forward_Resistor(mag_scaled, phase_scaled, rc_scaled);

        {
            float log_val = rc_scaled[0] * Resistor_target_scale[0] + Resistor_target_center[0];
            result.value_R = powf(10.0f, log_val);
        }
    }
    if (strcmp(result.label_str, "Capacitor") == 0) {
        float mag_log[N_MAG];
        log10_array(raw_mag15, N_MAG, mag_log);

        float mag_scaled[N_MAG];
        float phase_scaled[N_PHASE];
        robust_scale(mag_log, Capacitor_mag_center, Capacitor_mag_scale, N_MAG, mag_scaled);
        robust_scale(raw_phase15, Capacitor_phase_center, Capacitor_phase_scale, N_PHASE, phase_scaled);

        float rc_scaled[1];
        cnn_forward_Capacitor(mag_scaled, phase_scaled, rc_scaled);

        {
            float log_val = rc_scaled[0] * Capacitor_target_scale[0] + Capacitor_target_center[0];
            result.value_C = powf(10.0f, log_val);
        }
    }
    if (strcmp(result.label_str, "Series_RC") == 0) {
        float mag_log[N_MAG];
        log10_array(raw_mag15, N_MAG, mag_log);

        float mag_scaled[N_MAG];
        float phase_scaled[N_PHASE];
        robust_scale(mag_log, Series_RC_mag_center, Series_RC_mag_scale, N_MAG, mag_scaled);
        robust_scale(raw_phase15, Series_RC_phase_center, Series_RC_phase_scale, N_PHASE, phase_scaled);

        float rc_scaled[2];
        cnn_forward_Series_RC(mag_scaled, phase_scaled, rc_scaled);

        {
            float log_val = rc_scaled[0] * Series_RC_target_scale[0] + Series_RC_target_center[0];
            result.value_R = powf(10.0f, log_val);
        }
        {
            float log_val = rc_scaled[1] * Series_RC_target_scale[1] + Series_RC_target_center[1];
            result.value_C = powf(10.0f, log_val);
        }
    }
    if (strcmp(result.label_str, "Parallel_RC") == 0) {
        float mag_log[N_MAG];
        log10_array(raw_mag15, N_MAG, mag_log);

        float mag_scaled[N_MAG];
        float phase_scaled[N_PHASE];
        robust_scale(mag_log, Parallel_RC_mag_center, Parallel_RC_mag_scale, N_MAG, mag_scaled);
        robust_scale(raw_phase15, Parallel_RC_phase_center, Parallel_RC_phase_scale, N_PHASE, phase_scaled);

        float rc_scaled[2];
        cnn_forward_Parallel_RC(mag_scaled, phase_scaled, rc_scaled);

        {
            float log_val = rc_scaled[0] * Parallel_RC_target_scale[0] + Parallel_RC_target_center[0];
            result.value_R = powf(10.0f, log_val);
        }
        {
            float log_val = rc_scaled[1] * Parallel_RC_target_scale[1] + Parallel_RC_target_center[1];
            result.value_C = powf(10.0f, log_val);
        }
    }
    /* Neu label_str == "nothing" -> khong khop nhanh nao o tren -> giu R=0, C=0 */

    return result;
}


